appsmith.onReady(() => {
  appsmith.onModelChange(model => {
    // Use apk_data, fallback to cookies if necessary
    const apkData = model.apk_data || model.cookies || {};

    // 1. Consolidate Risk Reductions dynamically
    let remediations = [];

    // Check 1: AI / ML Dependencies (TensorFlow, OpenCV, etc.)
    const nativeCode = apkData?.android_api?.api_native_code?.files || {};
    let mlFound = false;
    Object.keys(nativeCode).forEach(path => {
      if (path.includes("tensorflow") || path.includes("mlmodel") || path.includes("opencv")) mlFound = true;
    });
    if (mlFound) {
      remediations.push({
        severity: "Critical",
        evidence: "Native AI/ML libraries (e.g., TensorFlow Lite) observed executing in background payload.",
        recommendation: "Remove unsanctioned ML dependencies from build, or declare explicit usage and model bounds in AI Governance Policy.",
        category: "AI Touchpoints"
      });
    }

    // Check 2: Unsanctioned Data Egress (Facebook / Trackers)
    let fbFound = false;
    let sensitiveTrackerFound = false;
    if (Array.isArray(apkData.trackers)) {
      apkData.trackers.forEach(t => {
        if (t.network && t.network.toLowerCase().includes("facebook")) fbFound = true;
        if (t.is_sensitive) sensitiveTrackerFound = true;
      });
    }
    if (fbFound) {
      remediations.push({
        severity: "Critical",
        evidence: "Social Graph telemetry (Facebook) observed in network egress paths.",
        recommendation: "Suppress Device ID and Advertising ID transmission in third-party SDK initialization parameters.",
        category: "Data Flow & Egress"
      });
    }
    if (sensitiveTrackerFound) {
      remediations.push({
        severity: "Warning",
        evidence: "Sensitive user identifiers flagged as highly eligible for external ingestion / egress.",
        recommendation: "Apply client-side tokenization or redaction wrapper around the PII prior to outbound payload construction.",
        category: "Data Eligibility"
      });
    }

    // Check 3: JS Interfaces / DOM Parsing Risks
    const jsInterfaces = apkData?.android_api?.api_javascript_interface_methods?.files || {};
    if (Object.keys(jsInterfaces).length > 0) {
      remediations.push({
        severity: "Critical",
        evidence: `Adversarial input bypass signal surfaced in ${Object.keys(jsInterfaces).length} exposed JavaScript interface(s).`,
        recommendation: "Implement robust localized input sanitization within the background worker script or WebViews before logic ingestion.",
        category: "Client-Side Logic"
      });
    }

    // Check 4: Dangerous Permissions (e.g., Audio, Phone State)
    let dangerousPermissions = [];
    if (Array.isArray(apkData.permissions)) {
      dangerousPermissions = apkData.permissions.filter(p => p.status === "dangerous");
    } else if (apkData.permissions && typeof apkData.permissions === 'object') {
      // Handle dictionary format if applicable
      Object.keys(apkData.permissions).forEach(k => {
        if (apkData.permissions[k].status === "dangerous") dangerousPermissions.push(k);
      });
    }
    if (dangerousPermissions.length > 0) {
      remediations.push({
        severity: "Warning",
        evidence: `Application requests ${dangerousPermissions.length} dangerous permissions (e.g., RECORD_AUDIO, READ_PHONE_STATE) that increase AI inference context scope.`,
        recommendation: "Audit and reduce dangerous permission scopes to enforce least-privilege for embedded data collection services.",
        category: "Endpoint Signals"
      });
    }

    // Check 5: Dynamic Dex Loading (Integrity)
    const dexLoading = apkData?.android_api?.api_dexloading?.files || {};
    if (Object.keys(dexLoading).length > 0) {
      remediations.push({
        severity: "Warning",
        evidence: "Dynamic code loading (Dex) functions detected, increasing risk of unsanctioned remote model injection.",
        recommendation: "Restrict dynamic execution capabilities or implement strict cryptographic signature checks on remotely fetched logic chunks.",
        category: "Client-Side Logic"
      });
    }

    // Fallback generic remediation if JSON payload is completely empty
    if (remediations.length === 0) {
      remediations.push({
        severity: "Safe",
        evidence: "Standard execution environment observed.",
        recommendation: "Continue monitoring runtime payload for anomalies.",
        category: "General"
      });
    }

    // 2. Sort to ensure Critical items are prioritized at the top
    remediations.sort((a, b) => {
      if (a.severity === "Critical" && b.severity !== "Critical") return -1;
      if (a.severity !== "Critical" && b.severity === "Critical") return 1;
      return 0;
    });

    // Enforce Top 10 Limit as requested in spec
    const top10 = remediations.slice(0, 10);

    // 3. Update Stats
    const criticalCount = top10.filter(r => r.severity === 'Critical').length;
    document.getElementById('critical-actions').innerText = criticalCount;
    const warningCount = top10.filter(r => r.severity === 'Warning').length;
    document.getElementById('warning-actions').innerText = warningCount;
    document.getElementById('total-actions').innerText = top10.length;

    // 4. Populate Table
    const tbody = document.getElementById('remediation-table-body');
    tbody.innerHTML = '';
    top10.forEach(item => {
      const tr = document.createElement('tr');

      // Severity
      const tdSeverity = document.createElement('td');
      const severityBadge = document.createElement('span');
      if (item.severity === 'Critical') severityBadge.className = 'badge badge-critical';else if (item.severity === 'Warning') severityBadge.className = 'badge badge-warning';else severityBadge.className = 'badge badge-safe';
      severityBadge.textContent = item.severity;
      tdSeverity.appendChild(severityBadge);

      // Evidence
      const tdEvidence = document.createElement('td');
      tdEvidence.innerHTML = `<span class="evidence-text">Observed:</span> ${item.evidence}`;

      // Recommendation
      const tdRec = document.createElement('td');
      tdRec.innerHTML = `<span class="recommendation-text">Action:</span> ${item.recommendation}`;

      // Category
      const tdCat = document.createElement('td');
      tdCat.innerHTML = `<code>${item.category}</code>`;
      tr.appendChild(tdSeverity);
      tr.appendChild(tdEvidence);
      tr.appendChild(tdRec);
      tr.appendChild(tdCat);
      tbody.appendChild(tr);
    });
  });
});

